#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+1;
int main(){
    long long n,x,a[maxn],b[maxn],ans=0;
    cin>>n>>x;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=n;i++)cin>>b[i];
    for(int i=1;i<=n;i++){
        if(x>=a[i]){
            x+=b[i];
            ans++;
        }
    }
    cout<<ans;
    return 0;
}
